A REST endpoint (external-facing) that calls a bank verification provider, with the payment service exposing the result internally over gRPC.

Simplest approach — a single endpoint that does micro-deposit verification (industry standard for bank account ownership):

```kotlin
// payment-service/src/main/kotlin/com/helios/payment/api/MerchantBankAccountController.kt

@RestController
@RequestMapping("/v1/merchants/{merchantId}/bank-accounts")
class MerchantBankAccountController(
    private val verificationService: BankAccountVerificationService
) {
    @PostMapping("/{bankAccountId}/verify")
    suspend fun requestVerification(
        @PathVariable merchantId: UUID,
        @PathVariable bankAccountId: UUID
    ): ResponseEntity<VerificationResponse> {
        val result = verificationService.initiate(merchantId, bankAccountId)
        return ResponseEntity.status(HttpStatus.ACCEPTED).body(result)
    }

    @PostMapping("/{bankAccountId}/verify/confirm")
    suspend fun confirmVerification(
        @PathVariable merchantId: UUID,
        @PathVariable bankAccountId: UUID,
        @RequestBody request: ConfirmVerificationRequest
    ): ResponseEntity<VerificationResponse> {
        val result = verificationService.confirm(merchantId, bankAccountId, request.amounts)
        return ResponseEntity.ok(result)
    }
}

data class ConfirmVerificationRequest(val amounts: List<BigDecimal>)

data class VerificationResponse(
    val bankAccountId: UUID,
    val status: VerificationStatus
)

enum class VerificationStatus { PENDING, VERIFIED, FAILED }
```

```kotlin
// payment-service/src/main/kotlin/com/helios/payment/service/BankAccountVerificationService.kt

@Service
class BankAccountVerificationService(
    private val bankAccountRepo: BankAccountRepository,
    private val paymentProvider: PaymentProviderClient // Stripe/Plaid wrapper
) {
    suspend fun initiate(merchantId: UUID, bankAccountId: UUID): VerificationResponse {
        val account = bankAccountRepo.findByIdAndMerchantId(bankAccountId, merchantId)
            ?: throw NotFoundException("Bank account not found")

        paymentProvider.sendMicroDeposits(account.externalId)

        bankAccountRepo.updateStatus(bankAccountId, VerificationStatus.PENDING)
        return VerificationResponse(bankAccountId, VerificationStatus.PENDING)
    }

    suspend fun confirm(
        merchantId: UUID,
        bankAccountId: UUID,
        amounts: List<BigDecimal>
    ): VerificationResponse {
        val account = bankAccountRepo.findByIdAndMerchantId(bankAccountId, merchantId)
            ?: throw NotFoundException("Bank account not found")

        val verified = paymentProvider.verifyMicroDeposits(account.externalId, amounts)
        val status = if (verified) VerificationStatus.VERIFIED else VerificationStatus.FAILED

        bankAccountRepo.updateStatus(bankAccountId, status)
        return VerificationResponse(bankAccountId, status)
    }
}
```

